/**
 * 全局状态管理工具
 * 用于管理用户登录状态和页面间状态同步
 */

// 全局状态
const globalState = {
	userInfo: null,
	isLoggedIn: false,
	listeners: [] // 状态变化监听器
}

/**
 * 获取全局状态
 */
export const getGlobalState = () => {
	return {
		userInfo: globalState.userInfo,
		isLoggedIn: globalState.isLoggedIn
	}
}

/**
 * 设置用户信息
 */
export const setUserInfo = (userInfo) => {
	globalState.userInfo = userInfo
	globalState.isLoggedIn = !!userInfo
	
	// 通知所有监听器
	notifyListeners()
}

/**
 * 清除用户信息
 */
export const clearUserInfo = () => {
	globalState.userInfo = null
	globalState.isLoggedIn = false
	
	// 通知所有监听器
	notifyListeners()
}

/**
 * 添加状态变化监听器
 */
export const addStateListener = (callback) => {
	globalState.listeners.push(callback)
	
	// 返回移除监听器的函数
	return () => {
		const index = globalState.listeners.indexOf(callback)
		if (index > -1) {
			globalState.listeners.splice(index, 1)
		}
	}
}

/**
 * 通知所有监听器状态已变化
 */
const notifyListeners = () => {
	globalState.listeners.forEach(callback => {
		try {
			callback(globalState.userInfo, globalState.isLoggedIn)
		} catch (error) {
			console.error('状态监听器执行错误:', error)
		}
	})
}

/**
 * 从本地存储同步状态
 */
export const syncFromStorage = () => {
	try {
		const userInfoStr = uni.getStorageSync('userInfo')
		if (userInfoStr) {
			const userInfo = JSON.parse(userInfoStr)
			setUserInfo(userInfo)
		} else {
			clearUserInfo()
		}
	} catch (error) {
		console.error('从本地存储同步状态失败:', error)
		clearUserInfo()
	}
}

/**
 * 同步到本地存储
 */
export const syncToStorage = () => {
	try {
		if (globalState.userInfo) {
			uni.setStorageSync('userInfo', JSON.stringify(globalState.userInfo))
		} else {
			uni.removeStorageSync('userInfo')
		}
	} catch (error) {
		console.error('同步到本地存储失败:', error)
	}
}
